-- Phase 1 teaching visuals: convert Modules 2–6 from plain-text lessons into
-- block-based content where every substantial topic carries a learning artifact
-- derived from the existing source facts (no invented content, no decorative emoji).
-- Idempotent: re-running overwrites video_url with the same JSON.

UPDATE lessons SET video_url = $blocks$[{"id":"m2-s1","type":"text","data":{"html":"<h3>How Infrastructure Evolved</h3><p><strong>Your goal:</strong> understand how IT infrastructure evolved, why businesses moved to the cloud, and where Leapswitch and CloudPe fit within the cloud ecosystem.</p><p>Infrastructure moved through three eras. In the traditional era businesses bought and managed their own servers — full control, but expensive, slow, and hard to scale (high hardware costs, long setup times, limited flexibility, ongoing maintenance, and downtime risk).</p>"}},{"id":"m2-evolution","type":"process_flow","data":{"eyebrow":"2.1 Infrastructure evolution","title":"From owned hardware to the cloud","steps":[{"title":"The traditional era","description":"Businesses buy and manage their own servers in offices or private data centers — full control, but costly and hard to scale.","icon":"server"},{"title":"The rise of virtualization","description":"Multiple virtual servers run on one physical machine, improving utilization, cutting cost, and speeding up deployment.","icon":"layers"},{"title":"The cloud revolution","description":"Organizations rent resources and pay only for what they use — shifting infrastructure from a capital expense to an operational one.","icon":"cloud"}]}},{"id":"m2-s2","type":"text","data":{"html":"<h3>Why Businesses Moved to the Cloud</h3><p>The shift to cloud changed how teams consume infrastructure across five areas.</p>"}},{"id":"m2-why","type":"feature_benefit","data":{"eyebrow":"2.2 Why businesses moved","title":"What the cloud changed","pairs":[{"feature":"Faster deployment","benefit":"Provision resources within minutes, not weeks.","icon":"zap"},{"feature":"Easy scalability","benefit":"Increase or decrease resources as demand changes.","icon":"scale"},{"feature":"Lower upfront costs","benefit":"Pay only for the resources consumed.","icon":"wallet"},{"feature":"Better accessibility","benefit":"Access from anywhere for distributed teams.","icon":"globe"},{"feature":"More focus on business","benefit":"Stop managing infrastructure, start building products.","icon":"rocket"}]}},{"id":"m2-s3","type":"text","data":{"html":"<h3>Cloud Deployment Models</h3><p>Cloud can be deployed three ways, each balancing control, security, and flexibility differently.</p>"}},{"id":"m2-deploy","type":"use_case_cards","data":{"eyebrow":"2.3 Deployment models","title":"Public, private, and hybrid","cases":[{"persona":"Shared","title":"Public cloud","description":"Infrastructure shared among multiple customers and managed by the provider. Easy to use, scalable, and needs no hardware investment.","icon":"globe","accent":"#6366F1"},{"persona":"Dedicated","title":"Private cloud","description":"Dedicated to a single organization for greater control, customization, and security where compliance or performance demands it.","icon":"lock","accent":"#A855F7"},{"persona":"Mixed","title":"Hybrid cloud","description":"Combines public and private — keep sensitive workloads private while using public cloud for flexibility and scale.","icon":"refresh","accent":"#14B8A6"}]}},{"id":"m2-s4","type":"text","data":{"html":"<h3>The Future of Cloud Infrastructure</h3><p>Five trends are shaping where the market is heading.</p>"}},{"id":"m2-future","type":"feature_benefit","data":{"eyebrow":"2.4 What’s next","title":"Trends shaping cloud","pairs":[{"feature":"AI & GPU cloud","benefit":"The rise of AI is creating growing demand for GPU-powered infrastructure.","icon":"cpu"},{"feature":"Hybrid cloud","benefit":"Many businesses run cloud and on-premises together.","icon":"refresh"},{"feature":"Edge computing","benefit":"Brings data processing closer to users and devices.","icon":"network"},{"feature":"Sovereign & local cloud","benefit":"Local providers help meet compliance requirements.","icon":"landmark"},{"feature":"Automation","benefit":"Platforms use more automation to reduce manual work.","icon":"settings"}]}},{"id":"m2-s5","type":"text","data":{"html":"<h3>IaaS, PaaS and SaaS</h3><p>The three cloud service models differ in how much of the technology stack the provider manages versus the customer.</p>"}},{"id":"m2-models","type":"comparison","data":{"eyebrow":"2.5 Service models","title":"Who manages what","columns":[{"label":"IaaS","subtitle":"Infrastructure as a Service","icon":"server","accent":"#6366F1","points":["Raw computing resources over the internet","Provider manages hardware, networking, data center","Customer manages OS, applications, data, runtime","Examples: CloudPe VMs, CloudPe GPU, AWS EC2, Azure VMs"]},{"label":"PaaS","subtitle":"Platform as a Service","icon":"layers","accent":"#10B981","points":["Managed platform for building and deploying apps","Provider manages hardware, OS, runtime, middleware","Customer manages applications and data only","Examples: CloudJiffy, Heroku, Google App Engine"]},{"label":"SaaS","subtitle":"Software as a Service","icon":"boxes","accent":"#F59E0B","points":["Ready-to-use software delivered over the internet","Provider manages everything","Customer just uses the software","Examples: Gmail, Microsoft 365, Salesforce, Zoom"]}]}},{"id":"m2-s6","type":"text","data":{"html":"<h3>Where Leapswitch & CloudPe Fit</h3><p>Leapswitch and CloudPe are strongest in the IaaS and PaaS segments — the building blocks teams use to run and scale workloads.</p><blockquote>Module summary: infrastructure evolved from owned hardware to virtualized environments to on-demand cloud. The cloud service models differ by how much the provider manages, and Leapswitch and CloudPe are strongest in IaaS and PaaS.</blockquote>"}},{"id":"m2-fit","type":"architecture_diagram","data":{"eyebrow":"2.6 Our position","title":"Leapswitch & CloudPe in the stack","layers":[{"name":"IaaS solutions","accent":"#6366F1","components":[{"label":"Bare Metal Servers","icon":"database"},{"label":"CloudPe Virtual Machines","icon":"server"},{"label":"CloudPe GPU Infrastructure","icon":"cpu"},{"label":"CloudPe Kubernetes","icon":"boxes"}]},{"name":"PaaS solutions","accent":"#10B981","components":[{"label":"CloudJiffy","icon":"zap"}]}]}}]$blocks$
WHERE order_index = 1 AND course_id IN (SELECT id FROM courses WHERE title ILIKE 'Sales Onboarding%');

UPDATE lessons SET video_url = $blocks$[{"id":"m3-s1","type":"text","data":{"html":"<h3>Leapswitch Infrastructure Portfolio</h3><p><strong>Your goal:</strong> understand Leapswitch’s core offerings, how they are grouped, and which solutions should receive the highest sales focus.</p><p>Leapswitch offers a complete ecosystem of infrastructure, cloud, platform, and supporting services — enabling businesses to run, manage, protect, and scale workloads through one unified portfolio rather than a single product. Every cloud service ultimately runs on physical infrastructure, and an SLA (Service Level Agreement) defines the availability commitment.</p>"}},{"id":"m3-stack","type":"architecture_diagram","data":{"eyebrow":"Infrastructure basics","title":"How the layers stack","layers":[{"name":"Customer applications","accent":"#6366F1","components":[{"label":"Websites","icon":"globe"},{"label":"Databases","icon":"database"},{"label":"Business systems","icon":"boxes"}]},{"name":"Cloud platform","accent":"#A855F7","components":[{"label":"On-demand resources","icon":"cloud"}]},{"name":"Physical servers","accent":"#10B981","components":[{"label":"Compute","icon":"cpu"},{"label":"Storage","icon":"hard-drive"},{"label":"Networking","icon":"network"}]},{"name":"Server racks","accent":"#F59E0B","components":[{"label":"Inside the data center","icon":"server"}]},{"name":"Data center","accent":"#ED3237","components":[{"label":"Houses the infrastructure","icon":"building"}]}]}},{"id":"m3-s2","type":"text","data":{"html":"<h3>Bare Metal Servers</h3><p>Dedicated physical servers assigned exclusively to a single customer. All hardware resources are reserved for one organization, giving maximum performance, control, and isolation. Customers choose Bare Metal for dedicated resources, consistent performance, greater control, and compliance.</p>"}},{"id":"m3-baremetal","type":"use_case_cards","data":{"eyebrow":"3.1 Bare Metal","title":"Best for","cases":[{"title":"Large databases","description":"Heavy, performance-sensitive data workloads.","icon":"database","accent":"#6366F1"},{"title":"ERP systems","description":"Business-critical systems needing consistent performance.","icon":"settings","accent":"#A855F7"},{"title":"High-traffic applications","description":"Apps that need dedicated, predictable capacity.","icon":"trending-up","accent":"#10B981"},{"title":"Gaming platforms","description":"Latency-sensitive, high-throughput workloads.","icon":"gauge","accent":"#F59E0B"},{"title":"AI workloads","description":"Compute-heavy training and inference.","icon":"brain","accent":"#ED3237"}]}},{"id":"m3-s3","type":"text","data":{"html":"<h3>GPU Cloud</h3><p>Scalable, on-demand GPU infrastructure without the need to purchase physical hardware — it lets businesses scale quickly while staying flexible and cost-efficient.</p>"}},{"id":"m3-gpu","type":"use_case_cards","data":{"eyebrow":"3.2 GPU Cloud","title":"Who uses GPU Cloud","cases":[{"title":"AI organizations","description":"Train and serve models at scale.","icon":"brain","accent":"#ED3237"},{"title":"Startups","description":"Access powerful compute without big upfront cost.","icon":"rocket","accent":"#6366F1"},{"title":"Software companies","description":"Run compute-heavy product workloads.","icon":"code","accent":"#10B981"},{"title":"Enterprises","description":"Add GPU capacity on demand.","icon":"building","accent":"#A855F7"},{"title":"Digital businesses","description":"Scale performance with demand.","icon":"globe","accent":"#14B8A6"}]}},{"id":"m3-s4","type":"text","data":{"html":"<h3>Private Cloud & Supporting Services</h3><p>A private cloud is dedicated to a single organization, giving greater control, customization, and security for strict compliance or performance needs. Around it sits a set of supporting services, each with a clear purpose.</p>"}},{"id":"m3-services","type":"feature_benefit","data":{"eyebrow":"3.4–3.5 Supporting services","title":"Service → purpose","pairs":[{"feature":"Backup Services","benefit":"Protect critical data.","icon":"shield-check"},{"feature":"Disaster Recovery","benefit":"Recover from major failures.","icon":"refresh"},{"feature":"Colocation","benefit":"Host customer-owned hardware.","icon":"building"},{"feature":"Managed Services","benefit":"Operational support.","icon":"wrench"},{"feature":"Hosting","benefit":"Website and application hosting.","icon":"globe"},{"feature":"Domains & SSL","benefit":"Online identity and security.","icon":"lock"}]}},{"id":"m3-s5","type":"text","data":{"html":"<h3>Current Sales Focus</h3><p>These products should receive the highest sales attention, in priority order. Supporting services should be positioned as additional value.</p><blockquote>Module summary: Leapswitch provides a full infrastructure portfolio — from Bare Metal and GPU Cloud to backup, network, and managed services. Lead with the priority products and position supporting services as added value.</blockquote>"}},{"id":"m3-priority","type":"process_flow","data":{"eyebrow":"Priority order","title":"Priority products for sales conversations","steps":[{"title":"CloudPe Virtual Machines","description":"Priority 1 — the core cloud offering.","icon":"server"},{"title":"GPU Infrastructure","description":"Priority 2 — high-demand AI/ML compute.","icon":"cpu"},{"title":"Bare Metal Servers","description":"Priority 3 — dedicated performance and control.","icon":"database"},{"title":"Kubernetes","description":"Priority 4 — container orchestration.","icon":"boxes"},{"title":"CloudJiffy","description":"Priority 5 — PaaS for fast app deployment.","icon":"zap"}]}}]$blocks$
WHERE order_index = 2 AND course_id IN (SELECT id FROM courses WHERE title ILIKE 'Sales Onboarding%');

UPDATE lessons SET video_url = $blocks$[{"id":"m4-s1","type":"text","data":{"html":"<h3>CloudPe VPS</h3><p><strong>Your goal:</strong> understand the CloudPe product portfolio and how each solution fits customer needs.</p><p>CloudPe is Leapswitch’s cloud platform that provides scalable, on-demand infrastructure without purchasing physical hardware — letting businesses scale quickly while staying flexible and cost-efficient.</p>"}},{"id":"m4-vps","type":"use_case_cards","data":{"eyebrow":"4.1 CloudPe VPS","title":"Who uses CloudPe","cases":[{"title":"Startups","description":"Scale quickly without large upfront commitments.","icon":"rocket","accent":"#6366F1"},{"title":"Software companies","description":"Flexible infrastructure for product workloads.","icon":"code","accent":"#10B981"},{"title":"Enterprises","description":"Reliable, on-demand capacity.","icon":"building","accent":"#A855F7"},{"title":"AI organizations","description":"Performance for compute-heavy workloads.","icon":"brain","accent":"#ED3237"},{"title":"Digital businesses","description":"Grow infrastructure with demand.","icon":"globe","accent":"#14B8A6"}]}},{"id":"m4-s2","type":"text","data":{"html":"<h3>CloudJiffy — PaaS</h3><p>CloudJiffy is Leapswitch’s Platform-as-a-Service offering that lets developers deploy applications without managing servers — reducing infrastructure complexity so teams ship faster.</p>"}},{"id":"m4-jiffy","type":"use_case_cards","data":{"eyebrow":"4.2 CloudJiffy","title":"Best for","cases":[{"title":"Web applications","description":"Deploy and run web apps without server management.","icon":"globe","accent":"#6366F1"},{"title":"SaaS platforms","description":"Run multi-tenant products on a managed platform.","icon":"boxes","accent":"#10B981"},{"title":"Development projects","description":"Spin up environments fast.","icon":"code","accent":"#A855F7"},{"title":"Rapid deployment","description":"Ship updates quickly with less overhead.","icon":"zap","accent":"#F59E0B"}]}},{"id":"m4-s3","type":"text","data":{"html":"<h3>Managed Services Add-Ons</h3><p>Add-on services that extend CloudPe, each with a clear purpose.</p><blockquote>Module summary: CloudPe (VPS) and CloudJiffy (PaaS) cover scalable infrastructure and fast app deployment, while managed add-ons protect data and simplify operations.</blockquote>"}},{"id":"m4-addons","type":"feature_benefit","data":{"eyebrow":"4.3 Add-ons","title":"Service → purpose","pairs":[{"feature":"Colocation","benefit":"Host customer-owned hardware.","icon":"building"},{"feature":"Backup Services","benefit":"Protect critical data.","icon":"shield-check"},{"feature":"Managed Services","benefit":"Operational support.","icon":"wrench"},{"feature":"Domains & SSL","benefit":"Online identity and security.","icon":"lock"}]}}]$blocks$
WHERE order_index = 3 AND course_id IN (SELECT id FROM courses WHERE title ILIKE 'Sales Onboarding%');

UPDATE lessons SET video_url = $blocks$[{"id":"m5-s1","type":"text","data":{"html":"<h3>Why Feature Selling Doesn’t Work</h3><p><strong>Your goal:</strong> learn how to translate technical features into customer benefits and measurable business outcomes.</p><p>Many new salespeople focus on explaining technical features. Customers are usually more interested in the outcomes those features create.</p>"}},{"id":"m5-vs","type":"comparison","data":{"eyebrow":"5.1 Feature vs value","title":"Two ways to say the same thing","columns":[{"label":"Feature-focused","icon":"message","accent":"#ED3237","points":["“We provide Kubernetes clusters and NVMe storage.”","Describes what the product has","Leaves the customer to infer the value"]},{"label":"Value-focused","icon":"target","accent":"#10B981","points":["“We help your applications run faster, scale more easily, and deliver a better customer experience.”","Describes the outcome the customer gets","Connects directly to business goals"]}]}},{"id":"m5-s2","type":"text","data":{"html":"<h3>The Three Levels</h3><p>Strong positioning climbs from what the product does, to the advantage it creates, to the measurable business outcome.</p>"}},{"id":"m5-levels","type":"process_flow","data":{"eyebrow":"5.2 Feature → Benefit → Value","title":"From feature to outcome","steps":[{"title":"Feature","description":"What the product does — e.g. SSD storage.","icon":"boxes"},{"title":"Benefit","description":"The advantage it creates — faster application performance.","icon":"zap"},{"title":"Business value","description":"The measurable outcome — better user experience and more customers retained.","icon":"trending-up"}]}},{"id":"m5-s3","type":"text","data":{"html":"<h3>Full Product Value Mapping</h3><p>Use this reference to translate each feature into the benefit and the business value it delivers.</p>"}},{"id":"m5-map","type":"feature_benefit","data":{"eyebrow":"5.3 Reference","title":"Feature → benefit → business value","pairs":[{"feature":"SSD Storage","benefit":"Faster application performance → better user experience.","icon":"hard-drive"},{"feature":"Auto Scaling","benefit":"Handles traffic growth automatically → supports business growth.","icon":"scale"},{"feature":"Backup Services","benefit":"Protects business data → reduced business risk.","icon":"shield-check"},{"feature":"Managed Support","benefit":"Faster issue resolution → reduced downtime.","icon":"headset"},{"feature":"GPU Infrastructure","benefit":"Faster model training → faster AI product development.","icon":"cpu"},{"feature":"Predictable Pricing","benefit":"Easier budgeting → reduced unexpected cloud expenses.","icon":"wallet"},{"feature":"India-Hosted Infrastructure","benefit":"Local compliance → better data control.","icon":"landmark"}]}},{"id":"m5-s4","type":"text","data":{"html":"<h3>Solution Mapping</h3><p>Match the customer’s challenge to the recommended solution.</p>"}},{"id":"m5-solutions","type":"scenario_cards","data":{"eyebrow":"5.4 Challenge → solution","title":"Match the need to the product","scenarios":[{"situation":"Training AI models is slow","recommended":"GPU Cloud","icon":"brain"},{"situation":"Traffic spikes during campaigns","recommended":"Scalable Cloud Infrastructure","icon":"trending-up"},{"situation":"Need reliable data backup","recommended":"Backup & Disaster Recovery","icon":"shield-check"},{"situation":"Want to deploy apps without managing servers","recommended":"CloudJiffy","icon":"zap"},{"situation":"Need dedicated, high-performance servers","recommended":"Bare Metal Servers","icon":"database"},{"situation":"Need flexible cloud resources","recommended":"CloudPe Virtual Machines","icon":"server"}]}},{"id":"m5-s5","type":"text","data":{"html":"<h3>Scenario Exercises</h3><p>Practice connecting a customer need to a solution and the business value it delivers.</p><blockquote>Module summary: customers buy business outcomes, not technical specifications. Always climb from feature to benefit to business value, and match the customer’s challenge to the right solution.</blockquote>"}},{"id":"m5-scenarios","type":"scenario_cards","data":{"eyebrow":"5.5 Practice","title":"Putting it together","scenarios":[{"situation":"“Training our AI models is taking too long.”","recommended":"GPU Cloud","note":"Need: faster AI training · Value: faster product development","icon":"brain"},{"situation":"“Traffic spikes during seasonal campaigns are affecting our website.”","recommended":"Cloud Infrastructure","note":"Need: scalability · Value: better customer experience","icon":"scale"},{"situation":"“We need a reliable backup strategy for business-critical data.”","recommended":"Backup & Disaster Recovery","note":"Need: data protection · Value: reduced business risk","icon":"shield-check"}]}}]$blocks$
WHERE order_index = 4 AND course_id IN (SELECT id FROM courses WHERE title ILIKE 'Sales Onboarding%');

UPDATE lessons SET video_url = $blocks$[{"id":"m6-s1","type":"text","data":{"html":"<h3>Department Responsibilities</h3><p><strong>Your goal:</strong> know the internal teams, their responsibilities, and when to involve them during the sales cycle.</p><p>Each team plays a specific role in delivering customer success. Knowing who does what helps you involve the right people at the right time.</p>"}},{"id":"m6-teams","type":"use_case_cards","data":{"eyebrow":"6.1 Departments","title":"Who does what","cases":[{"title":"Demand Generation","description":"Prospect identification, lead generation, LinkedIn outreach, cold calling, and meeting scheduling.","icon":"target","accent":"#6366F1"},{"title":"Inside Sales (ISR)","description":"Website inquiries, inbound leads, existing customer requests, and solution recommendations.","icon":"headset","accent":"#10B981"},{"title":"Business Development (BDM)","description":"Discovery meetings, opportunity management, requirements, and deal closure.","icon":"handshake","accent":"#A855F7"},{"title":"Presales Team","description":"Technical solution design, requirement analysis, architecture recommendations, and quotation support.","icon":"lightbulb","accent":"#F59E0B"},{"title":"Monitoring & Backup","description":"Monitors infrastructure, tracks performance, identifies issues proactively, and manages backup operations.","icon":"gauge","accent":"#14B8A6"},{"title":"Network Team","description":"Network management, IP allocation, connectivity, and coordination with data centers.","icon":"network","accent":"#6366F1"},{"title":"Infrastructure Team","description":"Server provisioning, deployment, hardware maintenance, and rack management.","icon":"server","accent":"#10B981"},{"title":"Support L1/L2/L3","description":"Resolves technical issues based on escalation levels and complexity.","icon":"wrench","accent":"#A855F7"},{"title":"CloudPe Support","description":"Supports CloudPe-specific customers and platform services.","icon":"cloud","accent":"#F59E0B"},{"title":"Customer Success","description":"Onboarding, retention, CRM management, customer experience, and relationships.","icon":"users","accent":"#14B8A6"},{"title":"Accounting & Billing","description":"Invoices, payments, collections, and billing-related activities.","icon":"wallet","accent":"#6366F1"},{"title":"Marketing Team","description":"Content creation, branding, campaigns, digital marketing, and market awareness.","icon":"message","accent":"#10B981"},{"title":"Data / Business Analyst","description":"Reporting, analytics, dashboards, and business insights.","icon":"trending-up","accent":"#A855F7"},{"title":"Development Team","description":"Product development, platform improvements, and feature enhancements.","icon":"code","accent":"#F59E0B"}]}},{"id":"m6-s2","type":"text","data":{"html":"<h3>What Customers Actually Care About</h3><p>Keep these priorities in mind in every conversation — customers buy business outcomes, not technical specifications.</p><blockquote>Module summary: many teams work together across the customer journey. Involve the right team at the right time, and frame everything around the outcomes customers care about.</blockquote>"}},{"id":"m6-care","type":"feature_benefit","data":{"eyebrow":"6.2 Customer priorities","title":"What customers value","pairs":[{"feature":"Reliability","benefit":"Applications and services stay available without unexpected downtime.","icon":"shield-check"},{"feature":"Performance","benefit":"Applications, websites, and workloads run smoothly and efficiently.","icon":"zap"},{"feature":"Cost control","benefit":"Predictable infrastructure costs and better visibility into spending.","icon":"wallet"},{"feature":"Security & compliance","benefit":"Solutions that help protect data and meet industry regulations.","icon":"shield"},{"feature":"Scalability","benefit":"Infrastructure that can grow alongside the business.","icon":"trending-up"},{"feature":"Support","benefit":"Providers who help when issues arise and understand business needs.","icon":"headset"}]}}]$blocks$
WHERE order_index = 5 AND course_id IN (SELECT id FROM courses WHERE title ILIKE 'Sales Onboarding%');
